import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, of } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Role, User } from '../models';

const TOKEN_KEY = 'auth_token';
const ACCESS_KEY = 'access_token';
const USER_KEY = 'user';
const ROLE_KEY = 'role';
const AUTH_FLAG = 'isAuthenticated';

// Mockup auth service. Runs fully offline: it fabricates a JWT-shaped token and
// stores a mock user so the guarded shell is reachable without a backend.
// The `service_agent` stage later replaces the mock bodies with real /api/auth calls.
@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;

  private _user = signal<User | null>(this.readUser());

  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => !!this._user());
  readonly role = computed<Role | null>(() => this._user()?.role ?? null);

  constructor(
    private http: HttpClient,
    private router: Router,
  ) {}

  /** Demo login — infers a role from the email prefix so the seeded demo users work offline. */
  login(email: string, _password: string): Observable<{ user: User; token: string }> {
    const role = this.roleFromEmail(email);
    const user: User = { id: 'u-' + role, email, role };
    this.persist(user);
    return of({ user, token: this.readToken()! });
  }

  /** Signup — first user becomes admin in the full_auth model. */
  signup(email: string, _password: string): Observable<{ user: User; token: string }> {
    const user: User = { id: 'u-new', email, role: 'admin' };
    this.persist(user);
    return of({ user, token: this.readToken()! });
  }

  /** One-click demo bypass used by the login page + screenshot capture. Logs in as admin. */
  demoLogin(): void {
    this.loginAs('admin');
  }

  /** Quick role switcher for reviewing role-scoped nav without a backend. */
  loginAs(role: Role): void {
    const email = `${role}@minierp.dev`;
    this.persist({ id: 'u-' + role, email, role });
    this.router.navigate(['/dashboard']);
  }

  logout(): void {
    [TOKEN_KEY, ACCESS_KEY, USER_KEY, ROLE_KEY, AUTH_FLAG, 'token'].forEach((k) =>
      localStorage.removeItem(k),
    );
    this._user.set(null);
    this.router.navigate(['/login']);
  }

  hasRole(...roles: Role[]): boolean {
    const r = this.role();
    return !!r && roles.includes(r);
  }

  private persist(user: User): void {
    const token = this.fakeToken(user);
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(ACCESS_KEY, token);
    localStorage.setItem('token', token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    localStorage.setItem(ROLE_KEY, user.role);
    localStorage.setItem(AUTH_FLAG, 'true');
    this._user.set(user);
  }

  private roleFromEmail(email: string): Role {
    const e = email.toLowerCase();
    if (e.startsWith('sales')) return 'sales';
    if (e.startsWith('purchasing')) return 'purchasing';
    return 'admin';
  }

  private fakeToken(user: User): string {
    const header = btoa(JSON.stringify({ alg: 'none', typ: 'JWT' }));
    const payload = btoa(JSON.stringify({ sub: user.id, email: user.email, role: user.role }));
    return `${header}.${payload}.mock`;
  }

  private readToken(): string | null {
    return localStorage.getItem(ACCESS_KEY);
  }

  private readUser(): User | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  }
}
